SELECT COUNT(codebase_id) AS total_codebases
FROM codebases
WHERE created_by = 0;

SELECT language_name
FROM languages
WHERE language_id = 1;

SELECT name
FROM codebases
WHERE upload_date > '2023-01-01';

SELECT created_by, COUNT(codebase_id) AS codebase_count
  FROM codebases
  GROUP BY created_by;
